let chalk;

export async function loadChalk() {
  if (chalk) return chalk;
  
  try {
    chalk = (await import('chalk')).default;
  } catch {
    // Fallback when chalk is not available (e.g., in browser environments)
    chalk = {
      green: (/** @type {string} */ text) => text,
      red: (/** @type {string} */ text) => text,
      blue: (/** @type {string} */ text) => text,
      dim: (/** @type {string} */ text) => text
    };
  }
  return chalk;
}